// items[0].json é o objeto "list" do Stripe com data=[...]
const list = items[0].json;
const subs = Array.isArray(list?.data) ? list.data : [];
const now = Math.floor(Date.now() / 1000);

// Validação estrita de telefone BR -> E.164, sem completar DDD.
// Aceita: "+55" + 10 ou 11 dígitos, ou "55" + 10/11 dígitos (sem +).
function toE164StrictBR(raw) {
  const s = String(raw || '').trim();
  if (!s) return { e164: '', ok: false, motivo: 'sem_telefone' };

  // "+55" + 10/11 dígitos
  if (/^\+55\d{10,11}$/.test(s)) return { e164: s, ok: true, motivo: '' };

  // "55" + 10/11 dígitos (sem "+")
  if (/^55\d{10,11}$/.test(s)) return { e164: `+${s}`, ok: true, motivo: '' };

  // qualquer outra coisa = inválido / possivelmente sem DDD
  return { e164: '', ok: false, motivo: 'telefone_mal_formatado_ou_sem_ddd' };
}

const out = [];

for (const s of subs) {
  const c = s.customer || {};
  const phone_raw = c.phone || c.metadata?.whatsapp || '';

  const { e164: phone_e164, ok: phone_ok, motivo: motivoFone } = toE164StrictBR(phone_raw);

  const status_stripe = s.status || '';
  const cancel_at     = s.cancel_at || null;
  const period_end    = s.current_period_end || null;
  const paid_until    = period_end ? new Date(period_end * 1000).toISOString().slice(0, 10) : '';

  // Ativo no Stripe (sem considerar telefone)
  const stripeAtivo = (status_stripe === 'active') &&
                      (!cancel_at) &&
                      (!period_end || period_end >= now);

  // Derivação do status_final
  let status_final = 'inativo';
  let motivo = '';

  if (!phone_raw) {
    status_final = 'validar';
    motivo = 'sem_telefone';
  } else if (!phone_ok) {
    status_final = 'validar';
    motivo = motivoFone; // mal formatado / sem DDD
  } else if (stripeAtivo) {
    status_final = 'ativo';
  } else {
    status_final = 'inativo';
    motivo = status_stripe !== 'active' ? `status_${status_stripe}` :
             cancel_at ? 'cancelado_ao_fim_do_ciclo' :
             (period_end && period_end < now) ? 'periodo_vencido' : '';
  }

  out.push({
    json: {
      name: c.name || '',
      email: c.email || '',
      phone_raw,              // exatamente como veio do Stripe
      phone_e164,             // só se válido sem "chute"
      stripe_customer_id: c.id || '',
      stripe_subscription_id: s.id,
      status_stripe,
      cancel_at,
      paid_until,
      status_final,           // ativo | inativo | validar
      motivo                  // ajuda a entender por que está "validar" ou "inativo"
    }
  });
}

return out;

const COUNTRY = '55';
const onlyDigits = s => String(s ?? '').replace(/\D/g, '').replace(/^0+/, '');
const toE164NoPlus = d => d ? (d.startsWith(COUNTRY) ? d : COUNTRY + d) : '';
const toJid = e164 => e164 ? `${e164}@s.whatsapp.net` : '';

const out = [];
const seen = new Set();

for (const { json } of items) {
  // prioriza o já normalizado; cai para o bruto se precisar
  const rawDigits = onlyDigits(json.phone_e164 || json.phone_raw);
  if (!rawDigits) continue;

  const e164 = toE164NoPlus(rawDigits); // sem sinal de +
  if (!e164) continue;

  if (seen.has(e164)) continue;
  seen.add(e164);

  const firstName = String(json.name || '').trim().split(/\s+/)[0] || '';

  out.push({
    json: {
      ...json,
      e164,                  // ex: 5511999999999
      jid: toJid(e164),      // ex: 5511999999999@s.whatsapp.net
      firstName
    }
  });
}

return out;

const ontem = new Date();
ontem.setDate(ontem.getDate() - 1);

const dia = String(ontem.getDate()).padStart(2, '0');
const mes = String(ontem.getMonth() + 1).padStart(2, '0');
const ano = ontem.getFullYear();

return {
  data_processamento: `${dia}/${mes}/${ano}`
};

const items = $input.all();
if (!items.length) {
  return [{ json: { prompt: "Nenhuma notícia foi processada." } }];
}

const data = items[0]?.json?.data_processamento || "DATA_NÃO_ENCONTRADA";

// Contexto curto para guiar o modelo (sem ficar gigantesco)
const MAX = 500;
const cut = s => (s || '').trim().slice(0, MAX);
const contexto = items.map(it => `• ${(it.json.titulo||'').trim()}\n${cut(it.json.legenda)}`).join("\n\n");

// Linhas FIXAS (não alterar)
const header1 = ``;
const header2 = `Segue resumo de notícias do dia *${data}*:\n\n`;
const header3 = `Acompanhe a nossa página no Instagram:\nhttps://www.instagram.com/imobjournal.ia\n\n`;

const prompt = `
Você é editor do briefing matinal da comunidade EMI (WhatsApp).
Produza UMA mensagem concisa, didática e **visual**, com base nas notícias de *${data}*.
Não liste notícia por notícia. Não inclua links (além do Instagram já fornecido). Não invente fatos.

BASE (referência; não copie literalmente):
${contexto}

FORMATO EXATO DA SAÍDA (mantenha as linhas fixas e a ordem):
${header1}${header2}${header3}[RESUMO CONECTADO EM BLOCOS]
- Estruture em **2 a 3 blocos**, cada um com **título em negrito + emoji** 
- Cada bloco deve ter **2 a 3 frases curtas**, explicando *o que aconteceu* e *por que importa para o corretor*.
- Use **1 emoji no título**. Separe os blocos com uma linha em branco.

*Como isso impacta para o incorporador?:*

- Escreva entre 1 e 2 paragrafos sobre como essas noticias impactam a vida do incorporador

*Manchetes do dia:*
- coloque em listas com emoji de 1️⃣,2️⃣, etc..

REGRAS:
- PT-BR, claro e objetivo; sem jargão.
- Priorize números/dados quando existirem; se faltarem, não invente.
- Não adicione seções além das especificadas.
`.trim();

return [{ json: { prompt } }];

// n8n Code node – pega o base64 do arquivo baixado no "Download file"
const binAll = $input.item.binary || {};

const key =
  binAll.imagem_final ? 'imagem_final' :
  (binAll.data ? 'data' : Object.keys(binAll)[0]);

if (!key) throw new Error(`Nenhum binário encontrado. Disponíveis: ${Object.keys(binAll).join(", ")}`);

const bin = binAll[key];
if (!bin?.data) throw new Error(`Binário na chave "${key}" não possui .data.`);

// ✅ Correto para Filesystem-v2 – lê o buffer real e converte para base64
const buffer = await this.helpers.getBinaryDataBuffer(0, key);
const base64 = buffer.toString('base64');

return {
  json: {
    base64Image: base64,
    mimeType: bin.mimeType || 'application/octet-stream',
    fileName: bin.fileName || 'arquivo'
  }
};

